from flask import Flask, render_template

app = Flask(__name__)

@app.route("/")
def home():
    user = {"name": "Alice", "is_admin": True}
    posts = [
        {"title": "Post 1", "date": "2024-01-01"},
        {"title": "Post 2", "date": "2024-01-15"}
    ]
    return render_template("home.html", user=user, posts=posts)
